/**
 * EVM wallet for paying storage costs.
 */
public protocol WalletProtocol: AnyObject, Sendable {
    
    /**
     * Get the wallet's public address (hex with 0x prefix).
     */
    func address()  -> String
    
    /**
     * Get the wallet's gas token balance (wei as decimal string).
     */
    func balanceOfGasTokens() async throws  -> String
    
    /**
     * Get the wallet's token balance (atto tokens as decimal string).
     */
    func balanceOfTokens() async throws  -> String
    
}
/**
 * EVM wallet for paying storage costs.
 */
open class Wallet: WalletProtocol, @unchecked Sendable {
    fileprivate let pointer: UnsafeMutableRawPointer!

    /// Used to instantiate a [FFIObject] without an actual pointer, for fakes in tests, mostly.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public struct NoPointer {
        public init() {}
    }

    // TODO: We'd like this to be `private` but for Swifty reasons,
    // we can't implement `FfiConverter` without making this `required` and we can't
    // make it `required` without making it `public`.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    required public init(unsafeFromRawPointer pointer: UnsafeMutableRawPointer) {
        self.pointer = pointer
    }

    // This constructor can be used to instantiate a fake object.
    // - Parameter noPointer: Placeholder value so we can have a constructor separate from the default empty one that may be implemented for classes extending [FFIObject].
    //
    // - Warning:
    //     Any object instantiated with this constructor cannot be passed to an actual Rust-backed object. Since there isn't a backing [Pointer] the FFI lower functions will crash.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public init(noPointer: NoPointer) {
        self.pointer = nil
    }

#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public func uniffiClonePointer() -> UnsafeMutableRawPointer {
        return try! rustCall { uniffi_ant_ffi_fn_clone_wallet(self.pointer, $0) }
    }
    // No primary constructor declared for this class.

    deinit {
        guard let pointer = pointer else {
            return
        }

        try! rustCall { uniffi_ant_ffi_fn_free_wallet(pointer, $0) }
    }

    
    /**
     * Create a wallet from an EVM private key.
     *
     * Uses the default Autonomi EVM network configuration.
     */
public static func fromPrivateKey(privateKey: String, rpcUrl: String, paymentTokenAddress: String, paymentVaultAddress: String)throws  -> Wallet  {
    return try  FfiConverterTypeWallet_lift(try rustCallWithError(FfiConverterTypeWalletError_lift) {
    uniffi_ant_ffi_fn_constructor_wallet_from_private_key(
        FfiConverterString.lower(privateKey),
        FfiConverterString.lower(rpcUrl),
        FfiConverterString.lower(paymentTokenAddress),
        FfiConverterString.lower(paymentVaultAddress),$0
    )
})
}
    

    
    /**
     * Get the wallet's public address (hex with 0x prefix).
     */
open func address() -> String  {
    return try!  FfiConverterString.lift(try! rustCall() {
    uniffi_ant_ffi_fn_method_wallet_address(self.uniffiClonePointer(),$0
    )
})
