/**
 * Result of storing a chunk on the network.
 */
public struct ChunkPutResult {
    /**
     * Hex-encoded chunk address (32 bytes).
     */
    public var address: String

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * Hex-encoded chunk address (32 bytes).
         */address: String) {
        self.address = address
    }
}

#if compiler(>=6)
extension ChunkPutResult: Sendable {}
#endif


extension ChunkPutResult: Equatable, Hashable {
    public static func ==(lhs: ChunkPutResult, rhs: ChunkPutResult) -> Bool {
        if lhs.address != rhs.address {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(address)
    }
}



