/**
 * Error type for client operations.
 */
public enum ClientError: Swift.Error {

    
    
    case InitializationFailed(reason: String
    )
    case NetworkError(reason: String
    )
    case PaymentError(reason: String
    )
    case InvalidInput(reason: String
    )
    case NotFound(reason: String
    )
    case AlreadyExists
    case WalletNotConfigured
    case InternalError(reason: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeClientError: FfiConverterRustBuffer {
    typealias SwiftType = ClientError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ClientError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .InitializationFailed(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 2: return .NetworkError(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 3: return .PaymentError(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 4: return .InvalidInput(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 5: return .NotFound(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 6: return .AlreadyExists
        case 7: return .WalletNotConfigured
        case 8: return .InternalError(
            reason: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ClientError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .InitializationFailed(reason):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .NetworkError(reason):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .PaymentError(reason):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .InvalidInput(reason):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .NotFound(reason):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(reason, into: &buf)
            
        
        case .AlreadyExists:
            writeInt(&buf, Int32(6))
        
        
        case .WalletNotConfigured:
            writeInt(&buf, Int32(7))
        
        
        case let .InternalError(reason):
            writeInt(&buf, Int32(8))
            FfiConverterString.write(reason, into: &buf)
            
        }
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeClientError_lift(_ buf: RustBuffer) throws -> ClientError {
    return try FfiConverterTypeClientError.lift(buf)
}

